18.1 Formula
For a set of weights \(w_1, \ldots, w_n\):
\[
\text{ESS} = \frac{\left(\sum_{i=1}^n w_i\right)^2}{\sum_{i=1}^n w_i^2}
\] {#eq-ess}
If all weights are equal, \(\text{ESS} = n\). If one weight dominates, \(\text{ESS} \approx 1\).

23.3 Implementation

library(quantreg)

# Grid of quantile levels
tau_grid &lt;- seq(0.05, 0.95, by = 0.05)

# Fit conditional quantile regressions by drug and time point
cqr_models &lt;- list()

for (t in 1:T_max) {
  col &lt;- paste0("A_", t)

  # Covariates available at this time point
  if (t == 1) {
    cov_cols &lt;- c("age", "male", "cd4_bl", "vl_bl")
  } else {
    cov_cols &lt;- c("age", "male", "cd4_bl", "vl_bl",
                  paste0("cd4_", t), paste0("vl_", t),
                  paste0("A_", t - 1))
  }

  fmla &lt;- as.formula(paste(col, "~", paste(cov_cols, collapse = " + ")))

  dat_A &lt;- dat_wide[dat_wide$Drug == 1, ]
  dat_B &lt;- dat_wide[dat_wide$Drug == 0, ]

  # Fit quantile regression at each tau for both drugs
  fits_A &lt;- lapply(tau_grid, function(tau) {
    suppressWarnings(rq(fmla, tau = tau, data = dat_A))
  })
  fits_B &lt;- lapply(tau_grid, function(tau) {
    suppressWarnings(rq(fmla, tau = tau, data = dat_B))
  })

  cqr_models[[t]] &lt;- list(fits_A = fits_A, fits_B = fits_B)
}

# Helper: given a vector of observed values and a matrix of conditional
# quantile predictions (rows = observations, cols = tau grid), find each
# observation's percentile rank by interpolation.
find_tau &lt;- function(a_obs, qmat) {
  n &lt;- length(a_obs)
  tau_out &lt;- numeric(n)
  for (i in seq_len(n)) {
    qs &lt;- qmat[i, ]
    if (a_obs[i] &lt;= qs[1]) {
      tau_out[i] &lt;- tau_grid[1]
    } else if (a_obs[i] &gt;= qs[length(qs)]) {
      tau_out[i] &lt;- tau_grid[length(tau_grid)]
    } else {
      tau_out[i] &lt;- approx(qs, tau_grid, xout = a_obs[i], rule = 2)$y
    }
  }
  tau_out
}

# Helper: given tau values and a matrix of Drug A conditional quantiles,
# return the corresponding adherence values by interpolation.
map_to_A &lt;- function(tau_vals, qmat_A) {
  n &lt;- length(tau_vals)
  a_out &lt;- numeric(n)
  for (i in seq_len(n)) {
    a_out[i] &lt;- approx(tau_grid, qmat_A[i, ], xout = tau_vals[i], rule = 2)$y
  }
  a_out
}

shift_conditional_qmap &lt;- function(data, trt) {
  t_idx &lt;- as.integer(gsub("A_", "", trt))
  a_obs &lt;- data[[trt]]
  a_shifted &lt;- a_obs

  is_b &lt;- data$Drug == 0
  if (any(is_b)) {
    mods &lt;- cqr_models[[t_idx]]

    # Predict conditional quantiles for Drug B patients under both models
    qmat_B &lt;- sapply(mods$fits_B, function(fit) predict(fit, newdata = data[is_b, ]))
    qmat_A &lt;- sapply(mods$fits_A, function(fit) predict(fit, newdata = data[is_b, ]))

    # Ensure quantiles are monotone (fix quantile crossing)
    for (i in seq_len(nrow(qmat_B))) {
      qmat_B[i, ] &lt;- sort(qmat_B[i, ])
      qmat_A[i, ] &lt;- sort(qmat_A[i, ])
    }

    # Step 1: find each Drug B patient's percentile rank in Drug B distribution
    tau_star &lt;- find_tau(a_obs[is_b], qmat_B)

    # Step 2: map to Drug A conditional quantile at that rank
    a_shifted[is_b] &lt;- map_to_A(tau_star, qmat_A)

    # Bound to [0.01, 0.99]
    a_shifted[is_b] &lt;- pmax(0.01, pmin(0.99, a_shifted[is_b]))
  }
  a_shifted
}


fit_cond &lt;- lmtp_sdr(
  data = dat_wide,
  trt = trt_vars,
  outcome = "Y",
  baseline = baseline,
  time_vary = time_vary,
  cens = cens_vars,
  shift = shift_conditional_qmap,
  mtp = TRUE,
  outcome_type = "binomial",
  learners_outcome = sl_outcome,
  learners_trt = sl_trt,
  folds = n_folds
)

contrast_cond &lt;- lmtp_contrast(fit_cond, ref = fit_observed, type = "additive")
cat("Conditional distribution mapping:\n")
#&gt; Conditional distribution mapping:
cat("  Shifted estimate:", round(fit_cond$estimate@x, 4), "\n")
#&gt;   Shifted estimate: 0.0755
cat("  Contrast vs observed:", round(contrast_cond$estimates$estimate, 4),
    " (95% CI:", round(contrast_cond$estimates$conf.low, 4),
    "to", round(contrast_cond$estimates$conf.high, 4), ")\n")
